var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……후우.","JPN":"……ふう。","ENG":"…Whew.","TWN":"……呼呼。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……모의 훈련 시스템 가동!","JPN":"……模擬訓練システム、稼働！","ENG":"...Activating simulation training system!","TWN":"……模擬訓練系統啟動！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>조디악 나이츠, 모의 훈련 시스템 가동 완료. </color>","JPN":"<color=#ffd34c>ゾディアックナイツ、模擬訓練システム稼働完了。</color>","ENG":"<color=#ffd34c>Zodiac Knights, simulation training system activation completed. </color>","TWN":"<color=#ffd34c>十二宮騎士團，模擬訓練系統啟動完畢。</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……사용자. 블루시프트, 피오네 로웰.","JPN":"……使用者。ブルーシフト、フィオネ・ローウェル。","ENG":"...User: Blue Shift, Fione Lowell.","TWN":"……使用人 藍移 菲奧尼。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>성문 인식, 성공하였습니다. </color>","JPN":"<color=#ffd34c>声紋認識に成功しました。</color>","ENG":"<color=#ffd34c>Voice recognition succeeded. </color>","TWN":"<color=#ffd34c>語音辨識，成功。</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>환영합니다, 피오네 로웰. </color>","JPN":"<color=#ffd34c>ようこそ、フィオネ・ローウェル。</color>","ENG":"<color=#ffd34c>Welcome, Fione Lowell. </color>","TWN":"<color=#ffd34c>歡迎你，菲奧尼。</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L21_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……훈련 설정. 방패 파괴 훈련 5단계.","JPN":"……訓練設定。盾破壊訓練5段階。","ENG":"...Select training: Shield Destruction Training Level 5.","TWN":"……設定訓練，盾牌破壞訓練第5階段。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>……훈련 확인. 홀로그래픽 실드 레벨 5 생성합니다. </color>","JPN":"<color=#ffd34c>……訓練確認。ホログラフィックシールド、レベル5を生成します。</color>","ENG":"<color=#ffd34c>...Training selection confirmed. Generating a Level 5 holographic shield... </color>","TWN":"<color=#ffd34c>……訓練確認。形成5級全像攝影護盾。</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L27_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"좋아, 오늘에야말로.","JPN":"よし、今日こそ……","ENG":"Alright, let's do this.","TWN":"很好，就是今天。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"STALKER_COUNTERCASE_NULL","text":{"KOREA":"피오네, 겨우 이런 것도 똑바로 못하는 거야?","JPN":"フィオネ、こんなこともちゃんとできないの？","ENG":"Fione, why can't you even do this?","TWN":"菲奧尼，你連這個也做不好嗎？"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"STALKER_COUNTERCASE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"STALKER_COUNTERCASE_NULL","text":{"KOREA":"하여간 넌 정말, 로웰 가의 수치라니까.","JPN":"まったく、だからあんたは本当にローウェル家の恥なのよ。","ENG":"Seriously, you're a disgrace to our family.","TWN":"你真是勞威爾家族之恥！"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"STALKER_COUNTERCASE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아니, 이젠 옛날과는 달라.","JPN":"いや、今は昔と違う。","ENG":"No, not anymore.","TWN":"不是，我現在和以前不一樣了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……간다!!","JPN":"……行くぞ！","ENG":"...Here I go!","TWN":"……來吧！！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"……피오네. 가문을 대표하는 기사가 되었으니 앞으로는 더욱 정진해야 할 거다.","JPN":"……フィオネ。家門を代表する騎士となったからには、これからもっと精進しなければならない。","ENG":"...Fione. Now that you've become the Knight of the family, you must work harder.","TWN":"……菲奧尼，既然你已經是代表家族的騎士，以後必須要更努力。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"이 애비는 이번 단장이 로웰 가문에서 나올 거라 믿어 의심치 않는다.","JPN":"父は、今度の団長がローウェル家から出ると信じている。","ENG":"I expect the next captain to be a Lowell.","TWN":"爸爸相信，新任的團長一定是出自我們勞威爾家族。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"……잘할 수 있겠지?","JPN":"……やれるな？","ENG":"...You won't disappoint me, will you?","TWN":"……你辦得到吧？"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……크읏!!","JPN":"……うっ！！","ENG":"...Gah!","TWN":"……咳咳！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_SMASH_ATTACK_SMALL"},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>훈련 결과. 총 9장의 실드를 관통하였습니다.</color>","JPN":"<color=#ffd34c>訓練結果。合計9枚のシールドを貫通しました。</color>","ENG":"<color=#ffd34c>Training results: Penetrated a total of 9 shields.</color>","TWN":"<color=#ffd34c>訓練結果。共穿越9個護盾。</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L47_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……쳇. 이번에도 마지막에 창의 무게 중심이 흔들렸군.","JPN":"……チッ。今回も最後に槍のバランスが崩れてしまった。","ENG":"…Tch, I let the lance sway at the very end, again.","TWN":"……嗟，這次也是最後一槍的重心不穩。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>다시 도전하시겠습니까?</color>","JPN":"<color=#ffd34c>再挑戦しますか？</color>","ENG":"<color=#ffd34c>Would you like to try again?</color>","TWN":"<color=#ffd34c>是否要重新挑戰？</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L1_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"후우, 이래선 다른 단원들을 볼 면목이 없군.","JPN":"はあ……これでは団員たちに合わせる顔がない。","ENG":"*Sigh...* I'm not even good enough to be deputy.","TWN":"呼，這樣下去，沒臉見其他團員呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L2_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"어쩌면, 나는 정말로 언니보다…….","JPN":"もしかしたら、私は本当に姉さんより……","ENG":"Maybe I'm really not as good as my sister...","TWN":"或許，我真的比姊姊……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아니, 아직 아니야.","JPN":"いや、まだだ。","ENG":"No, let's not go there, just yet.","TWN":"不，還不到時候。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"뚫지 못하면, 뚫을 때까지 도전하면 될 뿐.","JPN":"貫けないなら、貫けるまでやり続ければいい。","ENG":"If I can't do it, I'll try until I can.","TWN":"沒辦法穿越的話，那就挑戰到穿越為止！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"훈련 설정. 5단계…….","JPN":"訓練設定。5段階……","ENG":"Select training: Level 5...","TWN":"設定訓練，第5階段……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"늦은 밤까지 고생이 많군. 부단장.","JPN":"遅くまで頑張っているな、副団長。","ENG":"It's late, and you're still training, Deputy.","TWN":"練到這麼晚，辛苦了，副團長。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 부단장도 알고 있을텐데?","JPN":"だが、君もわかっているはずだ。","ENG":"But Deputy, don't you know?","TWN":"不過副團長你應該也知道吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"너무 과한 훈련은 오히려 독이라는 걸.","JPN":"やりすぎは体に毒だということを。","ENG":"Overtraining does more harm than good.","TWN":"欲速則不達。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님.","JPN":"団長。","ENG":"Captain.","TWN":"團長。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"어깨에 힘이 너무 많이 들어가 있어.","JPN":"肩に力が入りすぎだ。","ENG":"Your shoulders are too stiff.","TWN":"肩膀太用力。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"호흡도 필요 이상으로 너무 거칠고.","JPN":"呼吸も必要以上に乱れている。","ENG":"You're breathing too harshly, too.","TWN":"呼吸也太急促。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"흔히, 필요 이상의 과한 움직임은 잡념으로부터 나온다고들 하더군.","JPN":"必要以上の過度な動きは、雑念から来るものらしい。","ENG":"I've heard unnecessary thoughts make one move with more force than they need.","TWN":"我聽說，許多不必要的動作都是因雜念而起。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그리고 잡념을 떨쳐내는 데는 수다가 제격이지.","JPN":"そして、雑念を振り払うには人と会話をするのが効果的だ。","ENG":"And nothing beats chit chat when it comes to getting rid of such thoughts.","TWN":"而趕走雜念最好的辦法就是聊天。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"어떤가? 부단장. 나는 잠시 이야기를 들어줄 의향이 있는데.","JPN":"どうだ？　副団長。私なら、話を聞いてあげられるが。","ENG":"What do you say, Deputy? I could lend you an ear if you want.","TWN":"怎麼樣？副團長。我很想跟你聊聊。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……캔 커피를 너무 많이 뽑아버렸거든.","JPN":"……缶コーヒーを買いすぎてしまってな。","ENG":"...And I might have gotten too many coffee cans from the vending machine.","TWN":"……剛好我買了很多罐裝咖啡。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님은 거짓말이 서툴군요.","JPN":"団長は、嘘が下手ですね。","ENG":"Captain, you're such a bad liar.","TWN":"團長很不擅長說謊呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아시다시피, 무구의 선택을 받기 위해서는 기사의 자질이 있어야 합니다.","JPN":"ご存じのとおり、武具に選ばれるためには騎士としての資質が必要です。","ENG":"As you know, you have to have the makings of the knight to be chosen by the Armament.","TWN":"你也知道，必須具備騎士的資質，才能受到武具的揀選。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그리고 제 위로는 저보다 훨씬 자질이 뛰어난 언니가 한 명 있었죠.","JPN":"私には、より優れた資質を持つ姉が1人いました。","ENG":"I have an older sister who's much more talented than I am.","TWN":"而我有個資質比我更出色的姊姊。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"언니는…….","JPN":"姉は……","ENG":"And my sister…","TWN":"姊姊……"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"제가 아무리 노력해도 따라갈 수 없을 정도로 뛰어난 자질을 가졌습니다.","JPN":"私がどれだけ頑張っても追いつけないほど、抜きん出た資質の持ち主でした。","ENG":"I can never be as good as she, no matter how hard I try.","TWN":"姊姊的資質很好，無論我如何努力都追不上她。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그래서 가문 사람들 모두 언니가 창의 선택을 받을 것이라 믿어 의심치 않았죠.","JPN":"ローウェル家の人はみんな、槍に選ばれるのは姉だと固く信じていました。","ENG":"Everyone in my family was convinced that she'd be chosen by the Lance.","TWN":"所以家族的人全都深信，姊姊會得到武具的揀選。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"저는 그게 분했습니다.","JPN":"私は悔しかったです。","ENG":"That infuriated me.","TWN":"這令我很氣憤。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그래서 노력하고 또 노력했죠.","JPN":"だから努力し続けました。","ENG":"So, I trained and trained.","TWN":"所以我一直不斷地努力。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 어쩌면 속으로는 푸른 휘장을 걸치는 걸 포기하고 있었을지도 모릅니다.","JPN":"ですが、心のどこかでは、青い記章を我が身に付けることを……諦めていたのかもしれません。","ENG":"But on the inside, I had given up on wearing the blue insignia.","TWN":"但或許我心裡早就已經放棄要別上藍色徽章。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"왜냐하면…….","JPN":"なぜなら……","ENG":"Because...","TWN":"因為……"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"모두가 언니만을 바라보고 있었으니까요.","JPN":"みんな、姉だけを注目していましたから。","ENG":"Everyone was looking at my sister, not me.","TWN":"所有人的眼裡都只有姊姊。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 창의 선택은 달랐군.","JPN":"だが、槍の選択は違った。","ENG":"But the Lance chose the other one.","TWN":"可是槍的揀選卻不是這樣。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"네. 별의 무구, 별의 무구는 어째선지 언니가 아닌 저를 선택했죠.","JPN":"はい。星の武具はなぜか姉ではなく私を選びました。","ENG":"Yes. For some reason, the Star Armament chose me instead of her.","TWN":"沒錯，星之武具，不知道為什麼，是揀選我，而不是姊姊。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"제가 이 창의 힘을 처음 발동시켰을 때.","JPN":"私が初めてこの槍の力を発動させた時……","ENG":"When I first activated its power,","TWN":"我第一次使用這支槍的力量時，"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"가문 사람들은 저를 축복해주었습니다만…….","JPN":"家の人たちは私を祝福してくれました。","ENG":"my family members congratulated me, but...","TWN":"家族的人雖然表面上都祝福我……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"한편으로는 이렇게 생각했을 겁니다.","JPN":"でも、同時にこう思っていたでしょう。","ENG":"They probably had thought like this.","TWN":"但我知道，他們的心裡其實是這樣想的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>캐리 로웰이 선택 받았으면 더 좋았을 텐데</color> 라고.","JPN":"<color=#ffd34c>ケリー・ローウェルが選ばれたほうがよかったのに</color>と。","ENG":"<color=#ffd34c>It would have been better if Carrie was chosen</color>.","TWN":"<color=#ffd34c>如果是選中凱莉·勞威爾就更好了</color>。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"역사가 오래된 가문은 내부 사정이 복잡하군.","JPN":"歴史のある家門は、内情も複雑なものだな。","ENG":"I can never understand the internal matters of such old families.","TWN":"歷史悠久的家族，情況好像都複雜。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……단장님은 어떻습니까.","JPN":"……団長はどうですか。","ENG":"...What about you, Captain?","TWN":"……團長你呢？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님께서는 그 자리와, 그 검이 무겁지 않으십니까?","JPN":"団長はその地位と剣が重いと感じたことはありませんか？","ENG":"Don't you feel pressured by your position and the Sword?","TWN":"團長不覺得那個位置和那把劍很沉重嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"아니라고 하면 거짓말이겠지.","JPN":"ないと言えば嘘になる。","ENG":"I'd be lying if I said no.","TWN":"我若說不會那是騙人的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 기꺼이 짊어져야 하는 무게라고 생각해.","JPN":"しかし、これは私が背負うべき重さだと考えている。","ENG":"But it's a weight I'm happy to carry.","TWN":"不過我認為這是必須背負的沉重。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"왜냐하면 이 검이 나를 선택하였을 때, 나 스스로도 이 길을 걷겠다고 다짐했으니까.","JPN":"この剣が私を選んだ時、私自身もこの道を進むと決めたからだ。","ENG":"Because when the Sword chose me, I chose this path.","TWN":"因為這把劍選中我時，我自己也下定決心要走這條路。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그렇군요. 단장님은 강하군요.","JPN":"そうですか……団長はお強いですね。","ENG":"I see. You're so strong, Captain.","TWN":"原來如此，團長你很強大。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 저는… 역시 단장님처럼 강하지 못합니다.","JPN":"ですが私は……やはり、団長ほど強くはなれません。","ENG":"But… I'm not as strong as you.","TWN":"可是我……不像團長你那麼強大。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"어쩌면 나는 그저 운이 좋아서 이 창의 선택을 받은 게 아닐까?","JPN":"もしかしたら、単純に運がよかったから槍に選ばれたのではないか。","ENG":"What if it was a fluke that the Lance chose me?","TWN":"我會不會只是運氣好才被這把槍選中的？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"언니가 이 자리에 있다면 더 잘해내지 않았을까?","JPN":"この場にいたのが姉だったら、もっと上手くやれていたのではないか。","ENG":"Wouldn't Carrie make a better deputy than I ever could?","TWN":"要是換成姊姊的話，她會不會做得更好？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……제 의지와 상관 없이, 이따금 그런 생각을 품게 되더군요.","JPN":"……私の意思とは関係なく、こんなことを考えてしまうのです。","ENG":"...I can't help but ask these questions of myself sometimes.","TWN":"……有時候，我會不由自主地產生這樣的想法。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"부단장은 한 가지 착각을 하고 있군.","JPN":"副団長は1つ勘違いをしているな。","ENG":"Deputy, you're mistaken.","TWN":"副團長，你搞錯了一件事。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……예?","JPN":"……はい？","ENG":"...Pardon?","TWN":"……什麼？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"별의 인도란 재능을 가진 자에게 펼쳐진 카펫 같은 게 아니야.","JPN":"星の導きというのは、才能ある者の足元に敷かれたカーペットのようなものではない。","ENG":"The Star Guide isn't a red carpet spread before someone who's talented.","TWN":"星星的指引，不是向有才能的人展開的道路。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"별의 선택을 받은 자네가 걸어온 족적이, 곧 별의 인도인 것이지.","JPN":"星に選ばれた君の足跡こそが、星の導きそのものなのだ。","ENG":"It is the footprints you leave behind you as you were chosen by the Star.","TWN":"而是獲得星星揀選的你走過的足跡，就是星星的指引。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그 길에 결코 우연 따위는 없어.","JPN":"その道に偶然など存在しない。","ENG":"There are no what-ifs on that path.","TWN":"那條路也絕對不是偶然的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"가문 사람들에게 자신이 어떻게 비쳐질지 두려운가?","JPN":"一族の目に自分がどう映るかを恐れているのか？","ENG":"Are you afraid of how your family members perceive you?","TWN":"你害怕家族的人會如何看待你嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"자네보다 언니가 더 잘할 수 있을 것 같다고?","JPN":"自分より姉のほうが適任だと？","ENG":"Do you think your sister is better than you?","TWN":"你覺得你姊姊會做得比你更好？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"틀렸어, 부단장.","JPN":"それは違うぞ、副団長。","ENG":"You're wrong, Deputy.","TWN":"你錯了，副團長。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그들은 그저 바라볼 수밖에 없어.","JPN":"彼らはただ見守るしかできないんだ。","ENG":"Your family members are just bystanders.","TWN":"他們只能看著，"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……자네라는 별이 지나가는 궤적을.","JPN":"……君という星が描く軌跡をね。","ENG":"They are watching the arc of the star, which is you, as it passes by.","TWN":"……你這顆星星劃過的軌跡。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그러니 주위의 시선이 아닌, 언제나 부단장이 옳다고 믿는 길을 따르도록.","JPN":"だから周りを気にするのではなく、常に副団長、君自身が信じる道に従いたまえ。","ENG":"You should follow what you believe is right, instead of what others think.","TWN":"所以，副團長，不要在意周圍人的眼光，只要走在你認爲是正確的道路上。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……단장님.","JPN":"……団長。","ENG":"...Captain.","TWN":"……團長。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그렇군요, 잘 알겠습니다.","JPN":"なるほど、よくわかりました。","ENG":"I see. I understand.","TWN":"原來如此，我明白了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사가 돼서 이런 자격지심에 휘둘려 좌절하고 있었다니, 저도 아직 멀었군요.","JPN":"こんな自責の念に振り回され、勝手に挫折するとは……騎士としてまだまだですね。","ENG":"I'm the knight, and I'm still letting my own insecurity sway me. I have a long way to go.","TWN":"成為騎士後，我竟然因為自卑而感到沮喪，看來我還差得遠呢。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"옳은 길을 걷기 위해 고민하고 망설이는 건 나쁘지 않아.","JPN":"正しい道を歩むために悩み、迷うことは悪いことではない。","ENG":"It's not a bad thing that you question yourself about what you're doing.","TWN":"為了走在正確的道路上而苦惱或猶豫，或許不是件壞事。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"단장! 왜 이렇게 늦어! 이러다 바비큐 다 타겠어!","JPN":"団長！　遅いよ！　バーベキューが全部焦げちゃうよ！","ENG":"Captain, what's taking you so long? The meat is burning on the grill!","TWN":"團長！你怎麼這麼慢！肉都要烤焦了啦！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING"},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……뭐, 그런 망설임 없이도 나아가는 사람도 있긴 하다만.","JPN":"……まあ、そんな迷いもなくどんどん突き進む人も、この世にはいるのだがな。","ENG":"...Well, some never question themselves about what they're doing.","TWN":"……嗯～雖然也有人是毫不猶豫勇往直前的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경? 그게 무슨 소립니까? 이런 오밤중에 뭘 먹는다고요?","JPN":"リブ卿？　どういうことですか？　こんな夜中に何を食べるんですか？","ENG":"Dame Liv? What are you talking about? What are you eating in the middle of the night?","TWN":"莉芙卿？你這話是什麼意思？這麼晚你是要吃什麼？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"으힉! 뭐야, 부단장! 왜 단장이랑 같이 있어?","JPN":"げっ！　副団長！　なんで団長といるの！？","ENG":"Heek! Deputy? What are you doing with the Captain?","TWN":"哎呀！什麼嘛，副團長！你為什麼跟團長在一起啦！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"하하, 그게 말이지…… 장을 봐왔는데 고기가 너무 싸서……","JPN":"アハハ、それが……買い物に行ったら、肉が安かったから……","ENG":"Hah hah, that's... I went to the grocery store and found this meat on sale…","TWN":"哈哈，是這樣的……我去買菜的時候，因為肉實在太便宜……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"이 신선한 걸 얼려 두기엔 너무 아깝잖아?","JPN":"新鮮な肉なのに、冷凍しちゃうのはもったいないでしょ？","ENG":"It's so fresh that I didn't want to just freeze it.","TWN":"這麼新鮮的肉，冰起來不是很可惜嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"근데, 부단장이 알면 안 된다고 할 게 뻔하고 그래서 몰래 먹으려다가……","JPN":"でも、副団長に話したらきっと駄目出しされると思って、だからこっそり食べようと……","ENG":"And I didn't want you to stop me from eating it, so...","TWN":"不過，副團長知道的話一定不會答應，所以想說偷吃掉……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"아! 이건 말하면 안 되는데!","JPN":"しまった！　これは言っちゃいけないやつだった！","ENG":"Oops, I shouldn't have said that.","TWN":"哎呀！這個不能說的！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"에헤헤, 그냥 하루만 봐주라.","JPN":"えへへ、今回だけ許して。","ENG":"Heh heh heh. Give me a break, will you?","TWN":"嘿嘿，今天就放過我吧～"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……태도는 글렀지만.","JPN":"……その態度、いただけませんね……","ENG":"...Even though you tried to hide things from me,","TWN":"……雖然態度很糟糕，"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"뭐, 특별히 오늘 하루는 봐드리도록 하죠.","JPN":"特別に今日だけは、目を瞑って差し上げます。","ENG":"I'll let it slide just this once.","TWN":"不過，今天就放你一馬吧！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"저, 정말? 먹어도 돼?!","JPN":"ほ、本当に？　食べていいの！？","ENG":"R-really? Can I eat it, then?","TWN":"真…真的嗎？可以吃嗎？！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"……그럼 부단장도 같이 먹자!","JPN":"……じゃあ、副団長も一緒に食べようよ！","ENG":"Then, why don't you join us, Deputy?","TWN":"……那副團長也一起來吃吧！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그 대신, 자신의 선택에 대한 책임은 져야 할 겁니다. 고기 한 점에 훈련 한 시간씩.","JPN":"その代わり、自分の選択に対する責任は取ってもらいます。肉一口当たり、訓練1時間です。","ENG":"But you'll have to be responsible for your choice. One hour of training for every slice of meat you eat.","TWN":"不過，你必須為自己的選擇負責。吃一塊肉要訓練一小時。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"앗, 너무 치사하잖아! 그런 조건을 걸다니!","JPN":"あっ、ずるい！　そんな条件つきだなんて！","ENG":"Gah, that's too much! I can't agree to that!","TWN":"什麼～真是卑鄙！竟然還附條件！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"뭐, 리브 경이라면 한 입에 밥 한 공기도 충분히 들어가지 않습니까.","JPN":"リブ卿は、ご飯1杯でも一口でいけるじゃないですか。","ENG":"Well, Dame Liv, you can put a whole bowl of rice in your mouth.","TWN":"反正莉芙卿一口就能吃下一碗飯不是嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그, 그야 그렇지만……","JPN":"そ、それはそうだけど……","ENG":"T-true, but...","TWN":"話…話是沒錯……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"에잇! 알겠으니까, 부단장도 같이 가자! 피할 수 없으면 즐기란 말도 있잖아?!","JPN":"ああもう、わかったから副団長も一緒に行こう！　こうなったら、とことん楽しんでやるっ！","ENG":"Gah! Okay, I'll do that. Now, let's go, Deputy. If you can't avoid it, you should enjoy it, right?","TWN":"討厭！好啦！副團長也一起來吃吧！反正既然躲不過，那就好好享受吧！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……그렇군요.","JPN":"……そうですか。","ENG":"...I see.","TWN":"……原來如此。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"가끔은… 가끔은 다 함께 웃고 즐기는 것도 괜찮을지도 모르겠습니다.","JPN":"たまには……たまには、皆で笑って楽しむのも悪くないかもしれませんね。","ENG":"Maybe it's okay to let my hair down and have fun with people every now and then.","TWN":"偶爾……偶爾像這樣，大家一起說說笑笑，或許也不錯。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"알겠습니다. 편한 옷으로 갈아입고 가도록 하죠.","JPN":"わかりました。楽な服装に着替えてきます。","ENG":"Okay, let me go change to something more comfortable first.","TWN":"好，我先去換件舒服的衣服再過去。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"으응? 단장…… 부단장이 왠지 이상하지 않아?","JPN":"あれっ……？　団長。今日の副団長、ちょっと変じゃない？","ENG":"Mm? Captain, doesn't the Deputy look strange to you?","TWN":"嗯？團長……你不覺得副團長怪怪的嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"평소의 부단장이 아닌데, 뭔가 좀 더 부드러워졌다고 해야 할까?","JPN":"いつもの副団長とは違って……何だか、丸くなったというか……？","ENG":"She's not being her usual self. She feels more... flexible.","TWN":"好像跟平時的副團長不太一樣，感覺好像變溫柔了？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……음, 그런 것 같군.","JPN":"……うむ、確かにそうだな。","ENG":"...Mm, I think you're right.","TWN":"……嗯，好像是。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};